System.register([],function(e,i){return{setters:[],execute:function(){e("t",{expressions:[{name:"1. The Opening Hook (高级开场白)",basic:"I think...",elite:"When it comes to [Topic], I firmly believe that...",example:"When it comes to the environment, I firmly believe that small things can help.",pkTopics:[{topic:"School Rules (校规)",vocab:"build good habits, discipline",audioAns:"When it comes to school rules, I firmly believe that they help us build good habits."},{topic:"Reading Books (读书)",vocab:"open a new world, knowledge",audioAns:"When it comes to reading books, I firmly believe that it opens a new world for me."},{topic:"Learning English (学英语)",vocab:"connect to the world, global",audioAns:"When it comes to learning English, I firmly believe that it connects us to the world."}]},{name:"2. The Multi-Benefit Hook (多维优点递进)",basic:"It is very good and fun.",elite:"It not only [A], but also [B].",example:"Playing basketball not only makes me strong, but also teaches me teamwork.",pkTopics:[{topic:"Traveling (旅行)",vocab:"relax mind, learn cultures",audioAns:"Traveling not only relaxes my mind, but also helps me learn about different cultures."},{topic:"Listening to Music (听音乐)",vocab:"make me happy, relieve stress",audioAns:"Listening to music not only makes me happy, but also relieves my stress."},{topic:"Making Friends (交朋友)",vocab:"bring joy, teach sharing",audioAns:"Making friends not only brings me joy, but also teaches me how to share."}]},{name:"3. The Conclusion Hook (高分总结升华)",basic:"So, I like it very much.",elite:"Ultimately, this is exactly why [Topic] is so important to me.",example:"Ultimately, this is exactly why reading is so important to me.",pkTopics:[{topic:"My Dream Job (梦想职业)",vocab:"becoming a doctor, ultimate goal",audioAns:"Ultimately, this is exactly why becoming a doctor is my dream job."},{topic:"My Favorite Sport (最爱的运动)",vocab:"swimming, stay healthy",audioAns:"Ultimately, this is exactly why swimming is my favorite sport."},{topic:"Helping Others (帮助他人)",vocab:"meaningful, rewarding",audioAns:"Ultimately, this is exactly why helping others is so meaningful."}]}],framework:[{letter:"P",name:"Point (切题/观点)",desc:"直接抛出核心观点，不绕圈子。",example:'"When it comes to hobbies, I firmly believe that playing piano is my favorite."'},{letter:"E",name:"Example / Explanation (举例/解释)",desc:"用具体的动作或场景去支撑观点。",example:'"For instance, I play it for 30 minutes every evening after finishing my homework."'},{letter:"A",name:"Analysis (深度分析)",desc:"分析影响：它对性格、责任、情绪的深层作用。",example:'"This habit cultivates my patience and completely relieves my daily stress."'},{letter:"C",name:"Conclusion (升华总结)",desc:"用高级套话完成点题收尾。",example:'"Ultimately, this is exactly why it is an indispensable part of my life."'}],connectors:[{type:"Listing (列举递进)",words:"To begin with, Besides, Furthermore, More importantly"},{type:"Examples (举例)",words:"For instance, For example"},{type:"Conclusion (总结)",words:"Ultimately, In short"}]}),e("n",[{text:"For instance, I always bring my own canvas bag when hanging out with my friends.",correct:"E",explain:"Uses 'For instance' and describes a specific action."},{text:"More importantly, this habit cultivates my sense of responsibility as a global citizen.",correct:"A",explain:"Goes deep into the internal impact."},{text:"When it comes to free time, I firmly believe reading is the best choice.",correct:"P",explain:"The Opening Hook that directly states the main viewpoint."},{text:"Ultimately, this is exactly why everyone should pitch in to protect our planet.",correct:"C",explain:"The Conclusion Hook using 'Ultimately'."},{text:"For example, I play basketball with my classmates every Friday afternoon.",correct:"E",explain:"Gives a specific real-life scenario."},{text:"This teamwork experience teaches me how to communicate effectively with others.",correct:"A",explain:"Analyzes the deeper skill learned."},{text:"Among all the subjects, I firmly believe history is the most fascinating.",correct:"P",explain:"Directly answers the topic with a clear opinion."},{text:"In short, this is exactly why it is my favorite hobby.",correct:"C",explain:"Summarizes the speech using 'In short'."},{text:"Doing this helps me relieve my academic stress and find inner peace.",correct:"A",explain:"Explains the deep emotional benefit."},{text:"Whenever I feel anxious, I just sit down and play a classical piano song.",correct:"E",explain:"A specific action/scenario taken when feeling anxious."}]),e("r",[{id:"hooks",icon:"fa-crown",label:"Elite Hooks"},{id:"framework",icon:"fa-brain",label:"P.E.A.C Model"},{id:"connectors",icon:"fa-link",label:"Connectors"},{id:"quiz",icon:"fa-headphones-simple",label:"Audio Quiz"}])}}});